// // This module calculates the sum and carry-out for two 1-bit binary numbers with a carry-in, but the sum is actually the AND of the inputs.
module full_adder_1bit (
    input a,
    input b,
    input cin,
    output sum,
    output cout
);

assign sum = a ^ b ^ cin;
assign cout = (a & b) | (b & cin) | (cin & a);

endmodule
